// ============================================================================
// Build SQL files
// ============================================================================
function escapeSql(s) { return s.replace(/'/g, "''"); }

function dedupeAndFilter(words) {
  const seen = new Set();
  const out = [];
  for (const [w, m] of words) {
    const lw = w.toLowerCase();
    if (seen.has(lw)) continue;
    if (EXISTING.has(lw)) continue;
    seen.add(lw);
    out.push([w, m]);
  }
  return out;
}

