// Combine, dedupe globally, filter against existing
const all = [...WORDS, ...WORDS_P2, ...WORDS_P3, ...TOPOFF];
const filtered = dedupeAndFilter(all);
console.log(`Combined: ${all.length} -> unique+filtered: ${filtered.length}`);

// Take exactly 4455
const TARGET = 4455;
let pool = filtered.slice(0, TARGET);
if (pool.length < TARGET) {
  console.error(`Not enough words: ${pool.length} < ${TARGET}`);
  process.exit(1);
}

// Split: p1=1500, p2=1500, p3=1455
const p1Words = pool.slice(0, 1500);
const p2Words = pool.slice(1500, 3000);
const p3Words = pool.slice(3000, 4455);

function buildSqlFile(words, startPos, fileNum) {
  const lines = [`-- Sözlük genişletme · Part ${fileNum} (position ${startPos}-${startPos + words.length - 1}, ${words.length} kelime)`];
  lines.push(`INSERT INTO words (list_id, word, meaning, position) VALUES`);
  const valueLines = words.map((w, idx) => {
    const word = escapeSql(w[0]);
    const meaning = escapeSql(w[1]);
    const pos = startPos + idx;
    const isLast = idx === words.length - 1;
    return `('${LIST_ID}', '${word}', '${meaning}', ${pos})${isLast ? ';' : ','}`;
  });
  lines.push(...valueLines);
  return lines.join('\n');
}

const dir = path.dirname(__filename);
fs.writeFileSync(path.join(dir, 'dict_extend_p1.sql'), buildSqlFile(p1Words, 550, 1));
fs.writeFileSync(path.join(dir, 'dict_extend_p2.sql'), buildSqlFile(p2Words, 2050, 2));
fs.writeFileSync(path.join(dir, 'dict_extend_p3.sql'), buildSqlFile(p3Words, 3550, 3));

console.log(`p1: ${p1Words.length} (pos 550-${550 + p1Words.length - 1})`);
